use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

fn realcompare(a: f64, b: f64) -> &'static str {
    // Compare using the six most significant digits rule.
    // Treat numbers as equal if they differ by at most 10^(e-5),
    // where e = floor(log10(max(|a|, |b|))).
    if a == b {
        return "EQ";
    }
    let max_abs = a.abs().max(b.abs());
    if max_abs == 0.0 {
        return "EQ";
    }
    let exp = max_abs.log10().floor();
    let tol = 10f64.powf(exp - 5.0);
    if (a - b).abs() <= tol {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

fn is_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "LT"
}
fn is_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "GT"
}
fn is_le(a: f64, b: f64) -> bool {
    matches!(realcompare(a, b), "LT" | "EQ")
}
fn is_ge(a: f64, b: f64) -> bool {
    matches!(realcompare(a, b), "GT" | "EQ")
}

#[derive(Clone, Copy)]
struct Point {
    x: f64,
    y: f64,
}

fn point_eq(a: Point, b: Point) -> bool {
    realcompare(a.x, b.x) == "EQ" && realcompare(a.y, b.y) == "EQ"
}

fn distance(a: Point, b: Point) -> f64 {
    ((a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y)).sqrt()
}

fn triangle_area(a: Point, b: Point, c: Point) -> f64 {
    0.5 * ((b.x - a.x) * (c.y - a.y) - (c.x - a.x) * (b.y - a.y)).abs()
}

fn angle_at_vertex(a: Point, vertex: Point, c: Point) -> Option<f64> {
    if point_eq(a, vertex) || point_eq(c, vertex) {
        return None;
    }
    let ux = a.x - vertex.x;
    let uy = a.y - vertex.y;
    let vx = c.x - vertex.x;
    let vy = c.y - vertex.y;
    let dot = ux * vx + uy * vy;
    let nu = (ux * ux + uy * uy).sqrt();
    let nv = (vx * vx + vy * vy).sqrt();
    if nu == 0.0 || nv == 0.0 {
        return None;
    }
    let mut cos_theta = dot / (nu * nv);
    if cos_theta > 1.0 {
        cos_theta = 1.0;
    } else if cos_theta < -1.0 {
        cos_theta = -1.0;
    }
    Some(cos_theta.acos())
}

fn point_line_distance(p: Point, a: Point, b: Point) -> f64 {
    if point_eq(a, b) {
        return distance(p, a);
    }
    let abx = b.x - a.x;
    let aby = b.y - a.y;
    let apx = p.x - a.x;
    let apy = p.y - a.y;
    let cross = (abx * apy - aby * apx).abs();
    let denom = (abx * abx + aby * aby).sqrt();
    cross / denom
}

fn required_circle_radius(a: Point, b: Point, c: Point) -> f64 {
    // Minimal circle radius enclosing three points.
    if point_eq(a, b) && point_eq(b, c) {
        return 0.0;
    }
    if point_eq(a, b) {
        return 0.5 * distance(a, c);
    }
    if point_eq(a, c) {
        return 0.5 * distance(a, b);
    }
    if point_eq(b, c) {
        return 0.5 * distance(a, b);
    }

    let ab = distance(a, b);
    let bc = distance(b, c);
    let ac = distance(a, c);
    let max_side = ab.max(bc).max(ac);

    let area = triangle_area(a, b, c);
    if realcompare(area, 0.0) == "EQ" {
        return 0.5 * max_side;
    }

    // Check for obtuse/right triangle using squared side lengths.
    let ab2 = ab * ab;
    let bc2 = bc * bc;
    let ac2 = ac * ac;
    if is_ge(ab2, bc2 + ac2) || is_ge(bc2, ab2 + ac2) || is_ge(ac2, ab2 + bc2) {
        return 0.5 * max_side;
    }

    // Acute triangle: circumradius.
    (ab * bc * ac) / (4.0 * area)
}

fn quadrant(p: Point) -> usize {
    // Priority I, II, III, IV for axis ambiguities.
    if realcompare(p.x, 0.0) != "LT" && realcompare(p.y, 0.0) != "LT" {
        1
    } else if realcompare(p.x, 0.0) == "LT" && realcompare(p.y, 0.0) != "LT" {
        2
    } else if realcompare(p.x, 0.0) != "GT" && realcompare(p.y, 0.0) == "LT" {
        3
    } else {
        4
    }
}

fn lic1(points: &[Point], length1: f64) -> bool {
    for i in 0..points.len() - 1 {
        if is_gt(distance(points[i], points[i + 1]), length1) {
            return true;
        }
    }
    false
}

fn lic2(points: &[Point], radius1: f64) -> bool {
    for i in 0..points.len() - 2 {
        let r = required_circle_radius(points[i], points[i + 1], points[i + 2]);
        if is_gt(r, radius1) {
            return true;
        }
    }
    false
}

fn lic3(points: &[Point], epsilon: f64) -> bool {
    for i in 0..points.len() - 2 {
        if let Some(angle) = angle_at_vertex(points[i], points[i + 1], points[i + 2]) {
            let low = PI - epsilon;
            let high = PI + epsilon;
            if is_lt(angle, low) || is_gt(angle, high) {
                return true;
            }
        }
    }
    false
}

fn lic4(points: &[Point], area1: f64) -> bool {
    for i in 0..points.len() - 2 {
        if is_gt(triangle_area(points[i], points[i + 1], points[i + 2]), area1) {
            return true;
        }
    }
    false
}

fn lic5(points: &[Point], q_pts: usize, quads: usize) -> bool {
    if q_pts == 0 || q_pts > points.len() {
        return false;
    }
    for start in 0..=points.len() - q_pts {
        let mut seen = [false; 4];
        for i in start..start + q_pts {
            let q = quadrant(points[i]);
            seen[q - 1] = true;
        }
        let distinct = seen.iter().filter(|&&b| b).count();
        if distinct > quads {
            return true;
        }
    }
    false
}

fn lic6(points: &[Point]) -> bool {
    for i in 0..points.len() - 1 {
        if is_lt(points[i + 1].x - points[i].x, 0.0) {
            return true;
        }
    }
    false
}

fn lic7(points: &[Point], n_pts: usize, dist: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    if n_pts < 3 || n_pts > points.len() {
        return false;
    }
    for start in 0..=points.len() - n_pts {
        let a = points[start];
        let b = points[start + n_pts - 1];
        for i in start..start + n_pts {
            let d = if point_eq(a, b) {
                distance(points[i], a)
            } else {
                point_line_distance(points[i], a, b)
            };
            if is_gt(d, dist) {
                return true;
            }
        }
    }
    false
}

fn lic8(points: &[Point], k_pts: usize, length1: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    let step = k_pts + 1;
    for i in 0..points.len() - step {
        if is_gt(distance(points[i], points[i + step]), length1) {
            return true;
        }
    }
    false
}

fn lic9(points: &[Point], a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let step1 = a_pts + 1;
    let step2 = b_pts + 1;
    for i in 0..points.len() - (step1 + step2) {
        let j = i + step1;
        let k = j + step2;
        let r = required_circle_radius(points[i], points[j], points[k]);
        if is_gt(r, radius1) {
            return true;
        }
    }
    false
}

fn lic10(points: &[Point], c_pts: usize, d_pts: usize, epsilon: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let step1 = c_pts + 1;
    let step2 = d_pts + 1;
    for i in 0..points.len() - (step1 + step2) {
        let j = i + step1;
        let k = j + step2;
        if let Some(angle) = angle_at_vertex(points[i], points[j], points[k]) {
            let low = PI - epsilon;
            let high = PI + epsilon;
            if is_lt(angle, low) || is_gt(angle, high) {
                return true;
            }
        }
    }
    false
}

fn lic11(points: &[Point], e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let step1 = e_pts + 1;
    let step2 = f_pts + 1;
    for i in 0..points.len() - (step1 + step2) {
        let j = i + step1;
        let k = j + step2;
        if is_gt(triangle_area(points[i], points[j], points[k]), area1) {
            return true;
        }
    }
    false
}

fn lic12(points: &[Point], g_pts: usize) -> bool {
    if points.len() < 3 {
        return false;
    }
    let step = g_pts + 1;
    for i in 0..points.len() - step {
        if is_lt(points[i + step].x - points[i].x, 0.0) {
            return true;
        }
    }
    false
}

fn lic13(points: &[Point], k_pts: usize, length1: f64, length2: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    let step = k_pts + 1;
    let mut found_gt = false;
    let mut found_lt = false;
    for i in 0..points.len() - step {
        let d = distance(points[i], points[i + step]);
        if is_gt(d, length1) {
            found_gt = true;
        }
        if is_lt(d, length2) {
            found_lt = true;
        }
        if found_gt && found_lt {
            return true;
        }
    }
    false
}

fn lic14(points: &[Point], a_pts: usize, b_pts: usize, radius1: f64, radius2: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let step1 = a_pts + 1;
    let step2 = b_pts + 1;
    let mut found_gt = false;
    let mut found_le = false;
    for i in 0..points.len() - (step1 + step2) {
        let j = i + step1;
        let k = j + step2;
        let r = required_circle_radius(points[i], points[j], points[k]);
        if is_gt(r, radius1) {
            found_gt = true;
        }
        if is_le(r, radius2) {
            found_le = true;
        }
        if found_gt && found_le {
            return true;
        }
    }
    false
}

fn lic15(points: &[Point], e_pts: usize, f_pts: usize, area1: f64, area2: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let step1 = e_pts + 1;
    let step2 = f_pts + 1;
    let mut found_gt = false;
    let mut found_lt = false;
    for i in 0..points.len() - (step1 + step2) {
        let j = i + step1;
        let k = j + step2;
        let area = triangle_area(points[i], points[j], points[k]);
        if is_gt(area, area1) {
            found_gt = true;
        }
        if is_lt(area, area2) {
            found_lt = true;
        }
        if found_gt && found_lt {
            return true;
        }
    }
    false
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let points: Vec<Point> = (0..input.numpoints)
        .map(|i| Point {
            x: input.x[i],
            y: input.y[i],
        })
        .collect();

    let p = &input.parameters;

    let mut cmv = vec![false; 15];
    cmv[0] = lic1(&points, p.length1);
    cmv[1] = lic2(&points, p.radius1);
    cmv[2] = lic3(&points, p.epsilon);
    cmv[3] = lic4(&points, p.area1);
    cmv[4] = lic5(&points, p.q_pts, p.quads);
    cmv[5] = lic6(&points);
    cmv[6] = lic7(&points, p.n_pts, p.dist);
    cmv[7] = lic8(&points, p.k_pts, p.length1);
    cmv[8] = lic9(&points, p.a_pts, p.b_pts, p.radius1);
    cmv[9] = lic10(&points, p.c_pts, p.d_pts, p.epsilon);
    cmv[10] = lic11(&points, p.e_pts, p.f_pts, p.area1);
    cmv[11] = lic12(&points, p.g_pts);
    cmv[12] = lic13(&points, p.k_pts, p.length1, p.length2);
    cmv[13] = lic14(&points, p.a_pts, p.b_pts, p.radius1, p.radius2);
    cmv[14] = lic15(&points, p.e_pts, p.f_pts, p.area1, p.area2);

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in (i + 1)..15 {
            let conn = input.lcm[i][j].as_str();
            let v = match conn {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => false,
            };
            pum[i][j] = v;
            pum[j][i] = v;
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&b| b);
        }
    }
    let launch = fuv.iter().all(|&b| b);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
